// ScraperCity returns an array of contact objects.
// Normalize each lead into a flat structure for Airtable.
const raw = Array.isArray($input.first().json) ? $input.first().json : ($input.first().json.contacts || $input.first().json.data || []);

const results = [];
for (const contact of raw) {
  results.push({
    json: {
      firstName: contact.first_name || contact.firstName || '',
      lastName: contact.last_name || contact.lastName || '',
      fullName: contact.name || `${contact.first_name || ''} ${contact.last_name || ''}`.trim(),
      jobTitle: contact.title || contact.job_title || '',
      company: contact.organization_name || contact.company || '',
      workEmail: contact.email || contact.work_email || '',
      personalEmail: contact.personal_email || '',
      phone: contact.phone || contact.primary_phone || '',
      linkedinUrl: contact.linkedin_url || '',
      city: contact.city || '',
      country: contact.country || '',
      companyWebsite: contact.account ? (contact.account.website_url || '') : (contact.website_url || '')
    }
  });
}

return results;
